             204,210,220,230,231,240,255,273,286,300,330,360,390,420,462,510,
             546,570,630,660,690,714,770,780,840,910,1001,1155,1230,1290,1386,
             1470,1710,1925,2002,2310,2431,2730,3003,3315,3990,4290,5005,6006]
    results = []
    for a1 in cases:
        r = run_case(a1, N=1500)
        results.append(r)
        flag = "OK " if r.get('ok') else "FAIL"
        if r.get('T'):
            print(f"{flag} a1={a1:6d} T={r['T']:4d} L={r['L']:8d} shrinks={r['shrinks']:4d} "
                  f"last={r['last_shrink']} finalM={r['finalM']} |H|={r['finalHsize']}")
        else:
            print(f"{flag} a1={a1}: {r}")
    nfail = sum(1 for r in results if not r.get('ok'))
    print(f"\n{nfail} failures out of {len(results)}")

"""Hunt for dangerous configurations: disjoint transversals of size >= 2 (could
lead to perpetual shrinkage), and record stable H structures."""
from math import gcd
from sympy import factorint
from explore1 import rad_primes, prod

def run(a1, N):
    b = rad_primes(a1)
    H = {frozenset([p]) for p in b}
    seq = [a1]
    shrinks = []
    dangerous = []
    for n in range(1, N):
        an = seq[-1]
        best = None
        for h in H:
            hv = prod(h)
            m = (an // hv + 1) * hv
            if best is None or m < best:
                best = m
        seq.append(best)
        b = rad_primes(best)
        cand = set()
        for h in H:
            if h & b:
                cand.add(h)
            else:
                for q in b:
                    cand.add(h | {q})
        cand = list(cand)
        Hnew = set()
        for t in cand:
            if not any(u < t for u in cand):
                Hnew.add(t)
        if Hnew != H:
            shrinks.append(n)
        # check for dangerous pair: disjoint, both size >= 2
        Hl = list(Hnew)
        for i in range(len(Hl)):
            for j in range(i+1, len(Hl)):
                if not (Hl[i] & Hl[j]) and len(Hl[i]) >= 2 and len(Hl[j]) >= 2:
                    dangerous.append((n, sorted(Hl[i]), sorted(Hl[j])))
        H = Hnew
    return seq, shrinks, H, dangerous

if __name__ == "__main__":
    # 1) Inspect stable H for interesting odd a1
    for a1 in [105, 1155, 1001, 385, 165, 195, 255, 455, 595, 665, 935, 1105, 1309, 1495, 1729, 1995]:
        seq, shrinks, H, dang = run(a1, 4000)
        print(f"a1={a1:5d}: #shrinks={len(shrinks):4d} last={shrinks[-1] if shrinks else None} "
              f"stableH={[sorted(h) for h in H]} dangerous_pairs={len(dang)}")
        if dang:
            print(f"    first dangerous: {dang[0]}")

"""Test structural conjectures about minimal transversals H_n.

C1: every h in H_n is a subset of some b_i = rad(a_i), i <= n.
C2: stable H is pairwise intersecting.
C3: shrinkage always stops.
"""
from math import gcd
from sympy import factorint
from explore1 import rad_primes, prod

def run(a1, N, test_C1=True):
    b_list = [rad_primes(a1)]
    H = {frozenset([p]) for p in b_list[0]}
    seq = [a1]
    shrinks = []
    C1_fail = []
    for n in range(1, N):
        an = seq[-1]
        best = None
        for h in H:
            hv = prod(h)
            m = (an // hv + 1) * hv
            if best is None or m < best:
                best = m
        seq.append(best)
        b = rad_primes(best)
        b_list.append(b)
        cand = set()
        for h in H:
            if h & b:
                cand.add(h)
            else:
                for q in b:
                    cand.add(h | {q})
        cand = list(cand)
        Hnew = set()
        for t in cand:
            if not any(u < t for u in cand):
                Hnew.add(t)
        if Hnew != H:
            shrinks.append(n)
        H = Hnew
        if test_C1:
            for h in H:
                if not any(h <= bi for bi in b_list):
                    C1_fail.append((n, sorted(h)))
    # pairwise intersecting?
    Hl = list(H)
    pw = all((Hl[i] & Hl[j]) for i in range(len(Hl)) for j in range(i+1, len(Hl)))
    return dict(a1=a1, shrinks=shrinks, H=H, pw=pw, C1_fail=C1_fail, seq=seq)

if __name__ == "__main__":
    import itertools, random
    random.seed(1)
    cases = list(range(2, 120)) + [105, 1155, 1001, 385, 165, 195, 255, 455, 595,
            665, 935, 1105, 1309, 1495, 1729, 1995, 2310, 3003, 4290, 5005,
            3315, 2431, 1925, 210, 420, 840, 1260, 1680, 2520]
    cases = sorted(set(cases))
    bad_C1 = 0
    not_pw = []
    not_stable = []
    for a1 in cases:
        r = run(a1, 2500, test_C1=True)
        if r['C1_fail']:
            bad_C1 += 1
            print(f"C1 FAIL a1={a1}: {r['C1_fail'][:3]}")
        if r['shrinks'] and r['shrinks'][-1] >= 2499:
            not_stable.append(a1)
        if not r['pw'] and r['shrinks'] and r['shrinks'][-1] < 2400:
            not_pw.append((a1, [sorted(h) for h in r['H']]))
    print(f"C1 failures: {bad_C1}")
    print(f"cases not stabilized by 2500: {not_stable}")
    print(f"stable-but-not-pairwise-intersecting: {not_pw}")

"""Check: is every h in H_n contained in some b_i for all sufficiently large n?
Track max n where containment fails. Also track potential functions."""
from math import gcd
from sympy import factorint
from explore1 import rad_primes, prod

def run(a1, N):
    b_list = [rad_primes(a1)]
    H = {frozenset([p]) for p in b_list[0]}
    seq = [a1]
    shrinks = []
    max_fail_n = -1
    maxHsize = 1
    for n in range(1, N):
        an = seq[-1]
        best = None
        for h in H:
            hv = prod(h)
            m = (an // hv + 1) * hv
            if best is None or m < best:
                best = m
        seq.append(best)
        b = rad_primes(best)
        b_list.append(b)
        cand = set()
        for h in H:
            if h & b:
                cand.add(h)
            else:
                for q in b:
                    cand.add(h | {q})
        cand = list(cand)
        Hnew = set()
        for t in cand:
            if not any(u < t for u in cand):
                Hnew.add(t)
